/**
 * MedX pagination runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Page navigation for inventory tables, order history, and audit log views.
 */
const PAGINATION_DEFAULTS = Object.freeze({
  pageSize: 25,
  pageSizeOptions: [10, 25, 50, 100],
  siblingCount: 1,
  boundaryCount: 1,
});

const paginationControllers = new Map();

function createPagination(id, totalItems, options = {}) {
  const pageSize = options.pageSize ?? PAGINATION_DEFAULTS.pageSize;
  const totalPages = Math.max(1, Math.ceil(totalItems / pageSize));
  const controller = {
    id,
    totalItems,
    pageSize,
    pageSizeOptions: options.pageSizeOptions ?? PAGINATION_DEFAULTS.pageSizeOptions,
    currentPage: clampPage(options.initialPage ?? 1, totalPages),
    totalPages,
    siblingCount: options.siblingCount ?? PAGINATION_DEFAULTS.siblingCount,
    onPageChange: typeof options.onPageChange === "function" ? options.onPageChange : null,
  };
  paginationControllers.set(id, controller);
  return controller;
}

function clampPage(page, totalPages) {
  return Math.min(totalPages, Math.max(1, page));
}

function setPage(id, page) {
  const controller = paginationControllers.get(id);
  if (!controller) return null;
  const previous = controller.currentPage;
  controller.currentPage = clampPage(page, controller.totalPages);
  if (controller.onPageChange && previous !== controller.currentPage) {
    controller.onPageChange({
      previous,
      current: controller.currentPage,
      pageSize: controller.pageSize,
    });
  }
  return controller.currentPage;
}

function setPageSize(id, pageSize) {
  const controller = paginationControllers.get(id);
  if (!controller) return null;
  controller.pageSize = pageSize;
  controller.totalPages = Math.max(1, Math.ceil(controller.totalItems / pageSize));
  controller.currentPage = clampPage(controller.currentPage, controller.totalPages);
  return controller;
}

function getPageRange(id) {
  const controller = paginationControllers.get(id);
  if (!controller) return null;
  const start = (controller.currentPage - 1) * controller.pageSize;
  const end = Math.min(start + controller.pageSize, controller.totalItems);
  return { start, end, total: controller.totalItems };
}

function buildPageNumbers(id) {
  const controller = paginationControllers.get(id);
  if (!controller) return [];
  const { currentPage, totalPages, siblingCount } = controller;
  const pages = new Set([1, totalPages, currentPage]);
  for (let i = 1; i <= siblingCount; i++) {
    pages.add(currentPage - i);
    pages.add(currentPage + i);
  }
  return Array.from(pages)
    .filter((p) => p >= 1 && p <= totalPages)
    .sort((a, b) => a - b);
}

function goToNextPage(id) {
  const controller = paginationControllers.get(id);
  if (!controller) return null;
  return setPage(id, controller.currentPage + 1);
}

function goToPreviousPage(id) {
  const controller = paginationControllers.get(id);
  if (!controller) return null;
  return setPage(id, controller.currentPage - 1);
}

async function runMedxPagination() {
  console.log("[medx:ui:pagination] runtime initialized");

  const changes = [];
  const inventory = createPagination("inventory-list", 1247, {
    pageSize: 25,
    onPageChange: (e) => changes.push(e.current),
  });

  goToNextPage("inventory-list");
  goToNextPage("inventory-list");
  setPageSize("inventory-list", 50);
  const range = getPageRange("inventory-list");
  const pages = buildPageNumbers("inventory-list");

  const orders = createPagination("order-history", 89, { pageSize: 10, initialPage: 3 });

  console.log(`[medx:ui:pagination] controllers=${paginationControllers.size}`);
  console.log("[medx:ui:pagination] range", `${range.start + 1}-${range.end} of ${range.total}`);
  console.log("[medx:ui:pagination] pages", pages.join(","));
  console.log(`[medx:ui:pagination] pageChanges=${changes.length}`);
  console.log("[medx:ui:pagination] bootstrap complete");
}

module.exports = runMedxPagination;
